class Solution {
    public int[] countBits(int n) {
        int[] ans = new int[n + 1];
        for (int i = 0; i <= n; i++) {
            ans[i] = (i & (i - 1)) == 0 ? 1 : ans[i & (i - 1)] + 1;
            // However, a more efficient way still exists
            // Let's try a DP approach with a different insight
        }
        // A more efficient way still exists
        int[] dp = new int[n + 1];
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            dp[i] = dp[i >> 1] + (i & 1);
        }
        return dp;
    }
}
